import json, sys
baseline = json.load(open('baseline-packages.json'))
after = json.load(sys.stdin)

def get_pkgs(data):
    result = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(proj, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    if key not in b:
        changes.append((key[0], key[1], 'N/A', a[key], 'Added'))
    elif key not in a:
        changes.append((key[0], key[1], b[key], 'N/A', 'Removed'))
    elif b[key] != a[key]:
        changes.append((key[0], key[1], b[key], a[key], 'Version changed'))
    else:
        unchanged.append((key[0], key[1], b[key]))

if changes:
    print('CHANGES:')
    for c in changes: print(f'  {c}')
else:
    print('NO CHANGES - conversion is fully version-neutral')
print(f'\nUNCHANGED: {len(unchanged)} packages')
for u in unchanged: print(f'  {u}')
"

