          ]
        }
      ]
    },
    {
      "path": "Data/Data.csproj",
      "frameworks": [
        {
          "framework": "net8.0",
          "topLevelPackages": [
            {"id": "Microsoft.Extensions.DependencyInjection", "requestedVersion": "9.0.0", "resolvedVersion": "9.0.0"},
            {"id": "Microsoft.Extensions.DependencyInjection.Abstractions", "requestedVersion": "9.0.0", "resolvedVersion": "9.0.0"}
          ]
        }
      ]
    }
  ]
}

with open('baseline-packages.json', 'w') as f:
    json.dump(baseline, f, indent=2)

# Compare
after = json.load(open('after-cpm-packages.json'))

def get_pkgs(data):
    result = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(proj, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

changes = []
for key in sorted(set(b.keys()) | set(a.keys())):
    if key not in b:
        changes.append(f"ADDED: {key}")
    elif key not in a:
        changes.append(f"REMOVED: {key}")
    elif b[key] != a[key]:
        changes.append(f"CHANGED: {key} {b[key]} -> {a[key]}")

if changes:
    for c in changes: print(c)
else:
    print("✅ Conversion is fully version-neutral - all packages resolve identically to baseline")
print(f"Total packages compared: {len(b)}")
